    node: bpy.types.ShaderNodeWireframe

    def __init__(
        self,
        size: InputFloat = 0.01,
        *,
        use_pixel_size: bool = False,
    ):
        super().__init__()
        key_args = {"Size": size}
        self.use_pixel_size = use_pixel_size
        self._establish_links(**key_args)

    @property
    def i_size(self) -> SocketLinker:
        """Input socket: Size"""
        return self.inputs.get("Size")

    class Outputs:
        __slots__ = ("_node",)

        def __init__(self, node: "Wireframe") -> None:
            self._node = node

        @property
        def fac(self) -> SocketLinker:
            """Output socket: Factor"""
            return self._node.outputs.get("Fac")  # type: ignore[return-value]

    @property
    def o(self) -> "Outputs":
        return Wireframe.Outputs(self)

    @property
    def use_pixel_size(self) -> bool:
        return self.node.use_pixel_size

    @use_pixel_size.setter
    def use_pixel_size(self, value: bool):
        self.node.use_pixel_size = value
